import Link from 'next/link';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { FileText, Clock, CheckCircle2, XCircle, Loader2 } from 'lucide-react';
import type { Document } from '@/types';
import { formatDistanceToNow } from 'date-fns';

const statusConfig = {
  pending: { label: 'Pending', icon: Clock, variant: 'secondary' as const, color: 'text-yellow-600' },
  processing: { label: 'Processing', icon: Loader2, variant: 'secondary' as const, color: 'text-blue-600' },
  completed: { label: 'Completed', icon: CheckCircle2, variant: 'default' as const, color: 'text-green-600' },
  failed: { label: 'Failed', icon: XCircle, variant: 'destructive' as const, color: 'text-red-600' },
};

interface DocumentCardProps {
  document: Document;
}

export function DocumentCard({ document }: DocumentCardProps) {
  const status = statusConfig[document.status];
  const StatusIcon = status.icon;

  return (
    <Link href={`/dashboard/documents/${document.id}`}>
      <Card className="hover:shadow-md transition-shadow cursor-pointer">
        <CardContent className="p-4">
          <div className="flex items-start gap-3">
            <div className="rounded-lg bg-blue-50 dark:bg-blue-950 p-2.5 shrink-0">
              <FileText className="h-5 w-5 text-blue-600 dark:text-blue-400" />
            </div>
            <div className="flex-1 min-w-0">
              <p className="font-medium truncate">{document.file_name}</p>
              <p className="text-xs text-muted-foreground mt-0.5">
                {formatDistanceToNow(new Date(document.created_at), { addSuffix: true })}
              </p>
            </div>
            <Badge variant={status.variant} className="shrink-0">
              <StatusIcon className={`h-3 w-3 mr-1 ${document.status === 'processing' ? 'animate-spin' : ''}`} />
              {status.label}
            </Badge>
          </div>
          {document.status === 'completed' && document.extracted_data && (
            <div className="mt-3 pt-3 border-t">
              <p className="text-xs text-muted-foreground">
                {Object.keys(document.extracted_data).length} fields extracted
              </p>
            </div>
          )}
        </CardContent>
      </Card>
    </Link>
  );
}
