import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { extractFromDocument } from '@/lib/openai';

export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { documentId, templateId } = await request.json();

    if (!documentId) {
      return NextResponse.json({ error: 'Document ID required' }, { status: 400 });
    }

    // Get document
    const { data: doc, error: docError } = await supabase
      .from('documents')
      .select('*')
      .eq('id', documentId)
      .single();

    if (docError || !doc) {
      return NextResponse.json({ error: 'Document not found' }, { status: 404 });
    }

    // Update status to processing
    await supabase
      .from('documents')
      .update({ status: 'processing' })
      .eq('id', documentId);

    const startTime = Date.now();

    try {
      // Download file from storage
      const { data: fileData, error: downloadError } = await supabase.storage
        .from('documents')
        .download(doc.file_url);

      if (downloadError || !fileData) {
        throw new Error('Failed to download file');
      }

      // Convert to base64
      const arrayBuffer = await fileData.arrayBuffer();
      const base64 = Buffer.from(arrayBuffer).toString('base64');

      // Build extraction prompt
      let prompt = 'Extract all relevant data fields from this document. For each field, provide a value and confidence score (0-1). Return as JSON.';

      // If template provided, use template fields
      if (templateId || doc.template_id) {
        const { data: template } = await supabase
          .from('extraction_templates')
          .select('*')
          .eq('id', templateId || doc.template_id)
          .single();

        if (template?.fields) {
          const fields = template.fields as Array<{ name: string; type: string; description: string; required?: boolean }>;
          const fieldDescs = fields
            .map((f) => `- "${f.name}" (${f.type}): ${f.description}${f.required ? ' [REQUIRED]' : ''}`)
            .join('\n');
          prompt = `Extract the following fields from this document:\n${fieldDescs}\n\nReturn a JSON object where each key is the field name and each value has "value" and "confidence" (0-1).`;
        }
      }

      // Call OpenAI
      const extractedData = await extractFromDocument(base64, prompt);

      const processingTime = Date.now() - startTime;

      // Update document with results
      await supabase
        .from('documents')
        .update({
          status: 'completed',
          extracted_data: extractedData,
          processing_time_ms: processingTime,
        })
        .eq('id', documentId);

      // Increment usage counter
      await supabase.rpc('increment_doc_usage', { org_id: doc.organization_id }).catch(() => {
        // Usage tracking is best-effort
      });

      return NextResponse.json({
        data: {
          documentId,
          status: 'completed',
          extractedData,
          processingTimeMs: processingTime,
        },
      });
    } catch (processError) {
      // Update status to failed
      await supabase
        .from('documents')
        .update({ status: 'failed' })
        .eq('id', documentId);

      throw processError;
    }
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Processing failed';
    return NextResponse.json({ error: message }, { status: 500 });
  }
}
