  return (
    <Link href={`/dashboard/documents/${document.id}`}>
      <Card className="hover:shadow-md transition-shadow cursor-pointer">
        <CardContent className="p-4">
          <div className="flex items-start gap-3">
            <div className="rounded-lg bg-blue-50 dark:bg-blue-950 p-2.5 shrink-0">
              <FileText className="h-5 w-5 text-blue-600 dark:text-blue-400" />
            </div>
            <div className="flex-1 min-w-0">
              <p className="font-medium truncate">{document.file_name}</p>
              <p className="text-xs text-muted-foreground mt-0.5">
                {formatDistanceToNow(new Date(document.created_at), { addSuffix: true })}
              </p>
            </div>
            <Badge variant={status.variant} className="shrink-0">
              <StatusIcon className={`h-3 w-3 mr-1 ${document.status === 'processing' ? 'animate-spin' : ''}`} />
              {status.label}
            </Badge>
          </div>
          {document.status === 'completed' && document.extracted_data && (
            <div className="mt-3 pt-3 border-t">
              <p className="text-xs text-muted-foreground">
                {Object.keys(document.extracted_data).length} fields extracted
              </p>
            </div>
          )}
        </CardContent>
      </Card>
    </Link>
  );
}

'use client';

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Download, RotateCcw } from 'lucide-react';
import type { ExtractedField } from '@/types';

interface ExtractionResultsProps {
  data: Record<string, ExtractedField>;
  documentId: string;
  onReprocess?: () => void;
  onExport?: (format: string) => void;
}

function getConfidenceColor(confidence: number) {
  if (confidence >= 0.9) return 'text-green-600 bg-green-50 dark:bg-green-950';
  if (confidence >= 0.7) return 'text-yellow-600 bg-yellow-50 dark:bg-yellow-950';
  return 'text-red-600 bg-red-50 dark:bg-red-950';
}

export function ExtractionResults({ data, documentId, onReprocess, onExport }: ExtractionResultsProps) {
  const fields = Object.entries(data);

  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between">
        <CardTitle className="text-lg">Extracted Data</CardTitle>
        <div className="flex gap-2">
          {onReprocess && (
            <Button variant="outline" size="sm" onClick={onReprocess}>
              <RotateCcw className="h-4 w-4 mr-1" />
              Re-process
            </Button>
          )}
          {onExport && (
            <Button variant="outline" size="sm" onClick={() => onExport('csv')}>
              <Download className="h-4 w-4 mr-1" />
              Export
            </Button>
          )}
        </div>
      </CardHeader>
      <CardContent>
        {fields.length === 0 ? (
          <p className="text-sm text-muted-foreground text-center py-8">
            No data extracted yet
          </p>
        ) : (
          <div className="space-y-3">
            {fields.map(([key, field]) => (
              <div key={key} className="flex items-start justify-between gap-4 py-2 border-b last:border-0">
                <div className="flex-1">
                  <p className="text-sm font-medium capitalize">
                    {key.replace(/_/g, ' ')}
                  </p>
                  <p className="text-sm text-muted-foreground mt-0.5">
                    {field.value !== null && field.value !== undefined
                      ? String(field.value)
                      : 'Not found'}
                  </p>
                </div>
                <Badge
                  variant="secondary"
                  className={getConfidenceColor(field.confidence)}
                >
                  {Math.round(field.confidence * 100)}%
                </Badge>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Card, CardContent } from '@/components/ui/card';
import { Plus, Trash2, GripVertical, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import type { TemplateField } from '@/types';
import { TEMPLATE_CATEGORIES } from '@/lib/constants';

interface TemplateEditorProps {
  organizationId: string;
  initialData?: {
    name: string;
    description: string;
    category: string;
    fields: TemplateField[];
  };
  templateId?: string;
}

export function TemplateEditor({ organizationId, initialData, templateId }: TemplateEditorProps) {
  const [name, setName] = useState(initialData?.name || '');
  const [description, setDescription] = useState(initialData?.description || '');
  const [category, setCategory] = useState(initialData?.category || 'custom');
  const [fields, setFields] = useState<TemplateField[]>(initialData?.fields || []);
  const [saving, setSaving] = useState(false);
  const router = useRouter();

  const addField = () => {
    setFields([...fields, { name: '', type: 'text', description: '', required: false }]);
  };

  const removeField = (index: number) => {
    setFields(fields.filter((_, i) => i !== index));
  };

  const updateField = (index: number, updates: Partial<TemplateField>) => {
    setFields(fields.map((f, i) => (i === index ? { ...f, ...updates } : f)));
  };

  const handleSave = async () => {
    if (!name.trim()) {
      toast.error('Template name is required');
      return;
    }
    if (fields.length === 0) {
      toast.error('Add at least one field');
      return;
    }

    setSaving(true);

    try {
      const url = templateId ? `/api/documents/templates/${templateId}` : '/api/documents/templates';
      const method = templateId ? 'PATCH' : 'POST';

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name,
          description,
          category,
          fields,
          organization_id: organizationId,
        }),
      });

      if (!res.ok) throw new Error('Failed to save template');

      toast.success(templateId ? 'Template updated' : 'Template created');
      router.push('/dashboard/templates');
      router.refresh();
    } catch {
      toast.error('Failed to save template');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="space-y-6 max-w-3xl">
      <div className="grid gap-4 sm:grid-cols-2">
        <div className="space-y-2">
          <Label htmlFor="name">Template Name</Label>
          <Input
            id="name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="e.g., Invoice Template"
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="category">Category</Label>
          <Select value={category} onValueChange={setCategory}>
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {TEMPLATE_CATEGORIES.map((cat) => (
                <SelectItem key={cat.value} value={cat.value}>
                  {cat.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      <div className="space-y-2">
        <Label htmlFor="description">Description</Label>
        <Textarea
          id="description"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder="Describe what this template extracts..."
          rows={2}
        />
      </div>

      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <Label className="text-base font-semibold">Extraction Fields</Label>
          <Button variant="outline" size="sm" onClick={addField}>
            <Plus className="h-4 w-4 mr-1" />
            Add Field
          </Button>
        </div>

        {fields.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground border rounded-lg border-dashed">
            <p className="text-sm">No fields defined yet</p>
            <p className="text-xs mt-1">Click "Add Field" to define extraction fields</p>
          </div>
        ) : (
          <div className="space-y-3">
            {fields.map((field, index) => (
              <Card key={index}>
                <CardContent className="p-4">
                  <div className="flex items-start gap-3">
                    <GripVertical className="h-5 w-5 text-muted-foreground mt-2 shrink-0 cursor-grab" />
                    <div className="flex-1 grid gap-3 sm:grid-cols-4">
                      <Input
                        placeholder="Field name"
                        value={field.name}
                        onChange={(e) => updateField(index, { name: e.target.value })}
                      />
                      <Select
                        value={field.type}
                        onValueChange={(v) => updateField(index, { type: v as TemplateField['type'] })}
                      >
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="text">Text</SelectItem>
                          <SelectItem value="number">Number</SelectItem>
                          <SelectItem value="date">Date</SelectItem>
                          <SelectItem value="currency">Currency</SelectItem>
                          <SelectItem value="boolean">Boolean</SelectItem>
                        </SelectContent>
                      </Select>
                      <Input
                        placeholder="Description"
                        value={field.description}
                        onChange={(e) => updateField(index, { description: e.target.value })}
                      />
                      <div className="flex items-center gap-3">
                        <div className="flex items-center gap-2">
                          <Switch
                            checked={field.required || false}
                            onCheckedChange={(checked) => updateField(index, { required: checked })}
                          />
                          <span className="text-xs text-muted-foreground">Required</span>
                        </div>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => removeField(index)}
                          className="text-destructive hover:text-destructive"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      <div className="flex gap-3 pt-4">
        <Button onClick={handleSave} disabled={saving}>
          {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
          {templateId ? 'Update Template' : 'Create Template'}
        </Button>
        <Button variant="outline" onClick={() => router.back()}>
          Cancel
        </Button>
      </div>
    </div>
  );
}

